import { MIDDLE_C, MIDDLE_C_FREQ, P_GLIDE } from './constants';
import { Signal } from './signal';

export const builtInSignals = {
  noise: () => Signal.new(() => Math.random() * 2 - 1),
  pinkNoise: () => {
    const BUFFER_SIZE = 16;
    const buffer = new Array(BUFFER_SIZE).fill(0);
    let sum = 0;
    let idx = 0;
    return Signal.new(() => {
      sum -= buffer[idx];
      buffer[idx] = 2 * Math.random() - 1;
      sum += buffer[idx];
      idx = (idx + 1) % BUFFER_SIZE;
      return sum / BUFFER_SIZE;
    });
  },
  noteNum0: () => Signal.new(synth => synth.noteNum),
  noteNum: () => Signal.new(synth => synth.noteNum + synth.params[P_GLIDE]),
  noteFreq0: () => Signal.new(synth => synth.noteFreq0),
  noteFreq: () => Signal.new(synth => synth.noteFreq0 * Math.pow(2, synth.params[P_GLIDE] / 12)),
  noteVel: () => Signal.new(synth => synth.noteVel),
  middleC: () => Signal.new(() => MIDDLE_C),
  middleCFreq: () => Signal.new(() => MIDDLE_C_FREQ),
  input: () => Signal.new((synth, inputs, frameIdx) => inputs[0]?.[0]?.[frameIdx] ?? 0),
};
