import { basicSetup } from 'codemirror';
import { EditorView, hoverTooltip, keymap } from '@codemirror/view';
import { EditorState } from '@codemirror/state';
import { search, searchKeymap } from '@codemirror/search';
import { bracketMatching, indentOnInput } from '@codemirror/language';
import { defaultKeymap, historyKeymap } from '@codemirror/commands';
import { lintGutter, setDiagnostics } from '@codemirror/lint';
import { CompilerErrors } from './compiler';
import { inlinedModules } from './inlined-modules';
import { msynthLib } from './msynth-lib';
import { getAiModules } from './ai-modules';
import { InlinedModule, Module } from './module';
import { generateModule } from './generate-module-code';
import { Patch } from './patches';
import { PatchPart } from './types';

interface Settings {
  parent: HTMLElement;
  onSaveVoiceCode(paramsToo: boolean, showErrors: (errors: CompilerErrors) => void): void;
  onSaveEffectsCode(paramsToo: boolean, showErrors: (errors: CompilerErrors) => void): void;
  onRevert(): void;
  onClose(): void;
  onNewAiModule: (name: string) => void;
}

export function initEditor({
  parent,
  onSaveVoiceCode,
  onSaveEffectsCode,
  onRevert,
  onClose,
  onNewAiModule,
}: Settings) {
  let patch: Patch | null = null;
  let patchEditPart: PatchPart = 'voice';

  const wrapper = document.createElement('div');
  wrapper.className = 'editor-wrapper';
  wrapper.style.display = 'none'; // toggled in render loop when editingPatch
  wrapper.style.flexDirection = 'column';
  wrapper.style.overflow = 'hidden';
  wrapper.style.pointerEvents = 'auto';
  parent.appendChild(wrapper);

  // CodeMirror stops its handler chain when the keymap handles a key (preventDefault + break),
  // so a domEventHandlers keydown after the keymap never runs and cannot stopPropagation.
  // Catch everything that originates inside the patch editor UI (including the button bar)
  // once it has bubbled out of the focused control, so window-level listeners never see it.
  const stopKeyboardFromLeavingEditor = (e: KeyboardEvent) => {
    const t = e.target;
    if (t instanceof Node && wrapper.contains(t)) {
      e.stopPropagation();
    }
  };
  wrapper.addEventListener('keydown', stopKeyboardFromLeavingEditor);
  wrapper.addEventListener('keyup', stopKeyboardFromLeavingEditor);

  const buttonBar = document.createElement('div');
  buttonBar.className = 'editor-button-bar';
  wrapper.appendChild(buttonBar);

  /** Left-click mousedown focuses buttons by default; prevent that so CodeMirror keeps focus. */
  function preventButtonStealingFocus(btn: HTMLButtonElement) {
    btn.addEventListener('mousedown', e => {
      if (e.button === 0) {
        // left click
        e.preventDefault();
      }
    });
  }

  const partSegment = document.createElement('div');
  partSegment.className = 'editor-patch-part-segment';
  partSegment.setAttribute('role', 'tablist');
  partSegment.setAttribute('aria-label', 'Patch section');
  buttonBar.appendChild(partSegment);

  const partButtons: HTMLButtonElement[] = [];

  function addPartButton(part: PatchPart, label: string) {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'editor-patch-part-btn';
    btn.textContent = label;
    btn.setAttribute('role', 'tab');
    btn.setAttribute('aria-selected', part === patchEditPart ? 'true' : 'false');
    preventButtonStealingFocus(btn);
    btn.addEventListener('click', () => setPatchEditPart(part));
    partSegment.appendChild(btn);
    partButtons.push(btn);
  }

  function setPatchEditPart(part: PatchPart) {
    patchEditPart = part;

    for (const btn of partButtons) {
      const isActive = btn.textContent === patchEditPart;
      btn.classList.toggle('editor-patch-part-btn--active', isActive);
      btn.setAttribute('aria-selected', isActive ? 'true' : 'false');
    }

    const newContents = !patch ? '' : part === 'voice' ? patch.voiceCode : patch.effectsCode;
    setContents(newContents.trim());
  }

  addPartButton('voice', 'voice');
  addPartButton('effects', 'effects');

  const buttonBarActions = document.createElement('div');
  buttonBarActions.className = 'editor-button-bar-actions';
  buttonBar.appendChild(buttonBarActions);

  const container = document.createElement('div');
  container.className = 'editor-container';
  container.style.flex = '1';
  container.style.minHeight = '0';
  container.style.overflow = 'hidden';
  wrapper.appendChild(container);

  const addButton = (label: string, onClick: () => void) => {
    const btn = document.createElement('button');
    btn.className = 'editor-button';
    btn.textContent = label;
    btn.type = 'button';
    preventButtonStealingFocus(btn);
    btn.addEventListener('click', onClick);
    buttonBarActions.appendChild(btn);
  };

  addButton('save code and params', () => save(true));
  addButton('save code only', () => save(false));
  addButton('revert', onRevert);
  addButton('list modules', listModules);
  addButton('gen module', genModule);
  addButton('×', onClose);

  const showModuleInfoOnHover = hoverTooltip((view, pos, side) => {
    const { from, to, text } = view.state.doc.lineAt(pos);
    let start = pos,
      end = pos;
    while (start > from && /\w/.test(text[start - from - 1])) {
      start--;
    }
    while (end < to && /\w/.test(text[end - from])) {
      end++;
    }
    if ((start === pos && side < 0) || (end === pos && side > 0)) {
      return null;
    }
    const name = text.slice(start - from, end - from);
    const aiModules = getAiModules();
    const module = inlinedModules[name] || msynthLib[name] || aiModules[name];
    if (!module) {
      return null;
    }
    return {
      pos: start,
      end,
      below: true,
      create(view) {
        const dom = document.createElement('div');
        dom.classList.add('module-info-tooltip');
        dom.textContent = toTemplate(module, name);
        if (module.description) {
          dom.appendChild(document.createElement('br'));
          dom.appendChild(document.createElement('br'));
          dom.appendChild(document.createTextNode(module.description));
        }
        return { dom };
      },
    };
  });

  function toTemplate(module: Module<any> | InlinedModule<any>, name: string) {
    let hasInput = false;
    const otherPsAndVs: string[] = [];
    for (const [name, v] of Object.entries(module.defaultParamValues)) {
      if (name === 'input') {
        hasInput = true;
        continue;
      }
      let vStr: string | null;
      if (typeof v === 'function') {
        const match = v.toString().match(/^\(\)\s*=>\s*scalar\s*\(\s*([\d.]+)\s*\)$/);
        vStr = match ? match[1] : null;
      } else {
        vStr = String(v);
      }
      otherPsAndVs.push(vStr == null ? name : `${name}: ${vStr}`);
    }
    return `${hasInput ? 'input ' : ''}${name}(${otherPsAndVs.join(', ')})`;
  }

  const extensions = [
    basicSetup,
    indentOnInput(),
    bracketMatching(),
    search({ caseSensitive: false, regexp: false }),
    lintGutter(),
    showModuleInfoOnHover,
    EditorView.updateListener.of(update => {
      if (update.docChanged) {
        clearErrors();
      }
    }),
    keymap.of([
      {
        key: 'Mod-s',
        preventDefault: true,
        run: () => {
          save(true);
          return true;
        },
      },
      {
        key: 'Mod-l',
        preventDefault: true,
        run: () => {
          listModules();
          return true;
        },
      },
      {
        key: 'Mod-m',
        preventDefault: true,
        run: () => {
          genModule();
          return true;
        },
      },
      ...historyKeymap,
      ...searchKeymap,
      ...defaultKeymap,
    ]),
    EditorView.theme({
      '&': {
        height: '100%',
        fontSize: '20px',
        backgroundColor: '#fff',
      },
      '.cm-scroller': {
        overflow: 'auto',
        height: '100%',
      },
    }),
  ];

  function listModules() {
    insertAndSelectText(moduleList());
  }

  async function genModule() {
    const description = getSelectionText();
    if (description.length === 0) {
      return;
    }

    const name = await generateModule(description);
    if (!name) {
      console.log(':(');
    } else {
      console.log('generated module', name);
      onNewAiModule(name);
      replaceSelection(name);
    }
  }

  const view = new EditorView({
    state: EditorState.create({
      doc: 'this is the source code for the synth',
      extensions,
    }),
    parent: container,
  });

  function getSelectionText() {
    const state = view.state;
    const { from, to } = state.selection.ranges[0];
    return state.doc.slice(from, to).toString();
  }

  function replaceSelection(text: string) {
    const state = view.state;
    const { from, to } = state.selection.ranges[0];
    view.dispatch({
      changes: { from, to, insert: text },
      selection: { anchor: from, head: from + text.length },
      scrollIntoView: true,
    });
  }

  function insertAndSelectText(textToInsert: string) {
    const state = view.state;
    const range = state.selection.ranges[0]; // Get the main selection range
    const from = range.from;

    // Dispatch a transaction with both changes and selection
    view.dispatch({
      changes: { from, insert: textToInsert },
      selection: { anchor: from, head: from + textToInsert.length }, // Select the inserted text
      scrollIntoView: true, // Ensure the selection is visible
    });
  }

  function moduleList() {
    const denyList = ['unary-', '+', '-', '*', '/', '%'];
    const aiModules = getAiModules();
    const names = [
      ...Object.keys(inlinedModules),
      ...Object.keys(msynthLib),
      ...Object.keys(aiModules),
    ].filter(name => !denyList.includes(name));
    let output = '';
    let lineLength = 0;
    for (let idx = 0; idx < names.length; idx++) {
      if (lineLength > 60) {
        output += '\n';
        lineLength = 0;
      } else if (output.length > 0) {
        output += ' ';
        lineLength++;
      }
      output += names[idx];
      lineLength += names[idx].length;
    }
    return output;
  }

  function save(paramsToo: boolean) {
    (patchEditPart === 'voice' ? onSaveVoiceCode : onSaveEffectsCode)(paramsToo, showError);
  }

  function setContents(contents: string) {
    view.setState(EditorState.create({ doc: contents, extensions }));
    clearErrors();
  }

  function clearErrors() {
    view.dispatch(setDiagnostics(view.state, []));
  }

  function showError(errors: CompilerErrors) {
    view.dispatch(
      setDiagnostics(
        view.state,
        errors.errors.map(error => ({
          from: error.interval.startIdx,
          to: error.interval.endIdx,
          severity: 'error',
          message: error.message,
        }))
      )
    );
  }

  return {
    view,
    container: wrapper,
    setPatch(newPatch: Patch) {
      patch = newPatch;
      setPatchEditPart('voice');
    },
  };
}
