import * as ui from './ui-constants';
import { ctx } from './canvas';

let materialTexturePattern: CanvasPattern | null = null;

function ensureMaterialTexture() {
  if (materialTexturePattern) return;
  const size = 64;
  const tex = document.createElement('canvas');
  tex.width = size;
  tex.height = size;
  const tctx = tex.getContext('2d')!;
  const id = tctx.getImageData(0, 0, size, size);
  for (let i = 0; i < id.data.length; i += 4) {
    const x = (i / 4) % size;
    const y = Math.floor(i / 4 / size);
    const n = ((x * 31 + y * 17) % 64) / 64;
    const v = 128 + Math.floor(n * 24 - 12);
    id.data[i] = id.data[i + 1] = id.data[i + 2] = v;
    id.data[i + 3] = 18;
  }
  tctx.putImageData(id, 0, 0);
  materialTexturePattern = ctx.createPattern(tex, 'repeat')!;
}

/** Draws a subtle material texture (grain + soft highlight) over a rounded rect. */
export function drawMaterialOverlay(
  x: number,
  y: number,
  w: number,
  h: number,
  radius = ui.RECTANGLE_RADIUS
) {
  ensureMaterialTexture();
  ctx.save();
  ctx.beginPath();
  ctx.roundRect(x, y, w, h, radius);
  ctx.clip();
  const grad = ctx.createLinearGradient(x, y, x + w, y + h);
  grad.addColorStop(0, 'rgba(255,255,255,0.12)');
  grad.addColorStop(0.4, 'rgba(255,255,255,0.04)');
  grad.addColorStop(1, 'rgba(0,0,0,0.06)');
  ctx.fillStyle = grad;
  ctx.fillRect(x, y, w, h);
  ctx.globalAlpha = 0.6;
  ctx.fillStyle = materialTexturePattern!;
  ctx.fillRect(x, y, w, h);
  ctx.globalAlpha = 1;
  ctx.restore();
}
