const noteFromKey = new Map([
  ['z', 57],
  ['s', 58],
  ['x', 59],
  ['c', 60],
  ['f', 61],
  ['v', 62],
  ['g', 63],
  ['b', 64],
  ['n', 65],
  ['j', 66],
  ['m', 67],
  ['k', 68],
  [',', 69],
  ['l', 70],
  ['.', 71],
  ['/', 72],
]);

export async function setUpKeyboard(
  noteOn: (note: number, velocity: number) => void,
  noteOff: (note: number, velocity: number) => void,
  pitchBend: (numSemitones: number) => void
) {
  window.addEventListener('keydown', e => {
    if (e.repeat) {
      return;
    }

    const note = noteFromKey.get(e.key);
    if (note) {
      noteOn(note, 127);
    }
  });

  window.addEventListener('keyup', e => {
    if (e.repeat) {
      return;
    }

    const note = noteFromKey.get(e.key);
    if (note) {
      noteOff(note, 127);
    }
  });
}
