export interface Position {
  x: number;
  y: number;
}

export const MODES = ['mpe', 'piano', 'string', 'strum'] as const;
export type Mode = (typeof MODES)[number];
export const isMode = (m: any): m is Mode => MODES.includes(m);

export const OCTAVES = [2, 1, 0, -1, -2] as const;
export type Octave = (typeof OCTAVES)[number];
export const isOctave = (o: any): o is Octave => OCTAVES.includes(o);

export type PatchPart = 'voice' | 'effects';

export interface PatchSettings {
  gain: number;
  mode: Mode;
  mono: boolean;
  octave: number;
  A: number;
  B: number;
  C: number;
  D: number;
  E: number;
  F: number;
  G: number;
  H: number;
  tempo?: number;
  triggerPeriod?: number;
  noteDuration?: number;
}

export type PatternName = 'A' | 'B';
export type PatternStepTiming = {
  duration: number; // fraction of a 4/4 measure (same unit as triggerPeriod in the worklet)
  restAfter: number;
};
export type Pattern = { notes: number[][]; rhythm?: PatternStepTiming[] };

export interface SequencerState {
  patternA: Pattern;
  patternB: Pattern;
  currPattern: PatternName;
  currStep: number;
  nextPattern: PatternName | '●';
  triggerPeriod: number; // fraction of a 4/4 measure per grid step (e.g., 1/8 = eighth-note grid)
  noteDuration: number; // between 0 and 1, a fraction of the trigger period
  swing: number;
  playing: boolean;
  recordingRhythmStepIdx: number | null;
}

export type SynthWorkletRole = 'voice' | 'effects';

export type MessageToSynthWorklet =
  | {
      command: 'init';
      role: SynthWorkletRole;
      /** One state array per voice (see VoiceState). */
      voiceStates: SharedArrayBuffer[];
      /** Single samples buffer shared by all of the synth's voices. */
      samples: SharedArrayBuffer;
      /** Single params buffer shared by all of the synth's voices and its effect. */
      sharedParams: SharedArrayBuffer;
    }
  | { command: 'load patch'; code: string; mono: boolean }
  | { command: 'load ai modules'; modules: { name: string; code: string }[] }
  | { command: 'process midi message'; data: Uint8Array }
  | { command: 'sampler: set num samples'; value: number } // useful for loading samples from the client
  | { command: 'sampler: start recording' }
  | { command: 'sampler: stop recording' }
  // Keep voice 0 evaluating its signals (silently) so the sampler tool can show
  // in/out/loop points even when no notes are playing. Only sent to the voice worklet.
  | { command: 'sampler: set preview'; value: boolean }
  | { command: 'sequencer: set curr pattern'; pattern: PatternName }
  | { command: 'sequencer: set next pattern'; pattern: PatternName | '●' }
  | {
      command: 'sequencer: set pattern steps';
      pattern: PatternName;
      steps: Pattern;
    }
  | { command: 'sequencer: set trigger period'; value: number }
  | { command: 'sequencer: set note duration'; value: number }
  | { command: 'sequencer: set swing'; value: number }
  | { command: 'sequencer: start' }
  | { command: 'sequencer: stop' }
  | { command: 'sequencer rhythm: start recording' }
  | { command: 'sequencer rhythm: cancel recording' }
  | { command: 'sequencer rhythm: finger down' }
  | { command: 'sequencer rhythm: finger up' };

export type MessageFromSynthWorklet =
  | { event: 'log'; message: string }
  | { event: 'sampler: num samples'; value: number }
  | { event: 'sequencer: state'; state: SequencerState }
  | {
      event: 'sequencer: step';
      pattern: PatternName;
      index: number;
      action: 'noteOn' | 'noteOff';
    };

export type MessageToTapeWorklet = {
  command: 'init';
  state: SharedArrayBuffer;
  clips: SharedArrayBuffer;
  clipSamples: SharedArrayBuffer[];
};

export type MessageFromTapeWorklet = { event: 'log'; message: string };
