import { SAMPLE_RATE } from './constants';
import { Signal } from './signal';
import { interpolatedRead } from './helpers';

const MAX_DELAY_SECONDS = 10;
const DELAY_BUFFER_SIZE = MAX_DELAY_SECONDS * SAMPLE_RATE;

// TODO: add support for multiple taps
// maybe delay(signal, t1, v1, t2, v2, ...)
export function delay(input: Signal, t: Signal) {
  const buffer = new Float32Array(DELAY_BUFFER_SIZE);
  let writePos = 0;
  return Signal.new(() => {
    const delaySamples = Math.min(t.value, MAX_DELAY_SECONDS) * SAMPLE_RATE;
    // The adjustment of 3 samples is needed b/c we're using hermite interpolation,
    // which can read from the "future" by up to 2 samples when delay = 0.
    const adjustmentForHermiteInterpolation = 3;
    let readPos = writePos - delaySamples - adjustmentForHermiteInterpolation;
    if (readPos < 0) {
      readPos += DELAY_BUFFER_SIZE;
    }
    buffer[writePos++] = input.value;
    if (writePos >= DELAY_BUFFER_SIZE) {
      writePos = 0;
    }
    return interpolatedRead(buffer, readPos);
  });
}
