import { toFrequency } from './helpers';

export const SQRT_2 = Math.sqrt(2);

export const AI_MODULES_KEY = 'ai-modules';
export const LAST_INPUT_DEVICE_KEY = 'last-input-device-id';
export const INPUT_DEVICE_GAIN_KEY_PREFIX = 'gain-value-for-';
export const DEFAULT_INPUT_GAIN = 4;

export const SAMPLE_RATE = 48_000;
export const NUM_FRAMES_PER_CHUNK = 128;

export const TAPE_MAX_FRAMES_PER_TRACK = 6 * 60 * SAMPLE_RATE;
export const TAPE_LENGTH_IN_FRAMES = 6 * 60 * SAMPLE_RATE;

export const TAPE_ARROW_SPEED_MAGNITUDE = 4;

export const SAMPLE_RATE_RECIP = 1 / SAMPLE_RATE;
export const TAU = 2 * Math.PI;

// Indices into a voice's state array (see VoiceState).
// First, we have slots for the parameters listed below.
// The last such slot is NUM_SAMPLER_STATES.
// Directly after that, we have that many sampler states (each has 5 fields: phase, in, out, loopIn, loopOut).
//
// Only genuinely per-voice state lives here. glide/slide/pressure are per-voice
// MPE expression (each finger bends/slides/presses independently). State that is
// identical across every voice and the effect (gain, tempo, the shared params
// live in a single shared array instead — see the SP_* indices below.
export const P_GLIDE = 0;
export const P_SLIDE = 1;
export const P_PRESSURE = 2;
/** Number of silent frames left before this voice is considered free; <= 0 means free. */
export const P_SILENCE_COUNTDOWN = 3;
export const P_MIDI_NOTE = 4;
/** Base note frequency (no glide applied). */
export const P_NOTE_FREQ0 = 5;
/** Note frequency with glide applied (kept up to date by the worklet for the UI). */
export const P_NOTE_FREQ = 6;
export const P_NOTE_VEL = 7;
/** Number of sampler states (each has 5 fields). */
export const NUM_SAMPLER_STATES = 8;

// Indices into the shared params array (see VoiceState). These hold state that
// is identical across all of a synth's voices and its effect (gain, tempo, and
// params A–H), so a single array backs them rather than a copy per
// voice — setting one is a single write that every voice + the effect sees.
export const SP_GAIN = 0;
export const SP_TEMPO = 1;
export const SP_PARAM_A = 2;
export const SP_PARAM_B = 3;
export const SP_PARAM_C = 4;
export const SP_PARAM_D = 5;
export const SP_PARAM_E = 6;
export const SP_PARAM_F = 7;
export const SP_PARAM_G = 8;
export const SP_PARAM_H = 9;
export const NUM_SHARED_PARAMS = 10;

/** Named refs that index into a voice's (per-voice) state array. */
export const VOICE_PARAM_NAMES = new Map([
  ['glide', P_GLIDE],
  ['slide', P_SLIDE],
  ['pressure', P_PRESSURE],
]);

/** Named refs that index into the shared params array (gain, tempo, A–H). */
export const SHARED_PARAM_NAMES = new Map([
  ['gain', SP_GAIN],
  ['tempo', SP_TEMPO],
  ['A', SP_PARAM_A],
  ['B', SP_PARAM_B],
  ['C', SP_PARAM_C],
  ['D', SP_PARAM_D],
  ['E', SP_PARAM_E],
  ['F', SP_PARAM_F],
  ['G', SP_PARAM_G],
  ['H', SP_PARAM_H],
]);

export const MIDDLE_C = 60;
export const MIDDLE_C_FREQ = toFrequency(MIDDLE_C);
