import {
  NUM_SAMPLER_STATES,
  NUM_SHARED_PARAMS,
  P_GLIDE,
  P_MIDI_NOTE,
  P_NOTE_FREQ,
  P_NOTE_FREQ0,
  P_NOTE_VEL,
  P_PRESSURE,
  P_SILENCE_COUNTDOWN,
  P_SLIDE,
  SAMPLE_RATE,
  SP_GAIN,
  SP_PARAM_A,
  SP_PARAM_B,
  SP_PARAM_C,
  SP_PARAM_D,
  SP_PARAM_E,
  SP_PARAM_F,
  SP_PARAM_G,
  SP_PARAM_H,
  SP_TEMPO,
} from './constants';

/** How long (in frames) a voice stays "busy" after its last audible output. */
const FULL_SILENCE_COUNTDOWN_FRAMES = Math.floor(SAMPLE_RATE / 2); // 500ms

const STATE_ARRAY_SIZE = 256;
// Sampler states live after the named slots: a count at NUM_NAMED_STATES, then
// groups of 5 (phase, in, out, loopIn, loopOut).
const MAX_NUM_SAMPLER_STATES = Math.floor((STATE_ARRAY_SIZE - NUM_SAMPLER_STATES) / 5);

export const SAMPLES_ARRAY_SIZE = 5 * 60 * SAMPLE_RATE; // 5 minutes of samples

/**
 * Object-oriented wrapper over the shared arrays that hold a single voice's state.
 * The same buffers are read/written by both the UI and the synth worklet, so both
 * sides hold a VoiceState and go through these methods rather than touching the
 * arrays directly.
 *
 * `_state` is per voice; `_samples` and `_sharedParams` are shared by all
 * voices (and the effect) in a synth.
 */
export default class VoiceState {
  /** Allocate a samples buffer to be shared by all of a synth's voices. */
  public static allocateSharedSamples(): Float32Array<any> {
    return new Float32Array<any>(new SharedArrayBuffer(SAMPLES_ARRAY_SIZE * 4));
  }

  /** Allocate the shared params buffer shared by all of a synth's voices and its effect. */
  public static allocateSharedParams(): Float32Array<any> {
    return new Float32Array<any>(new SharedArrayBuffer(NUM_SHARED_PARAMS * 4));
  }

  /** Create a new voice, sharing the given (per-synth) samples and params buffers. */
  public static newWithSamplesAndSharedParams(
    samples: Float32Array<any> = VoiceState.allocateSharedSamples(),
    sharedParams: Float32Array<any> = VoiceState.allocateSharedParams()
  ) {
    return new VoiceState(
      new Float32Array<any>(new SharedArrayBuffer(STATE_ARRAY_SIZE * 4)),
      samples,
      sharedParams
    );
  }

  /** Wrap existing shared buffers (used by the worklet, which receives them via init). */
  public static fromStateAndSamplesAndSharedParamsArrays(
    state: Float32Array<any>,
    samples: Float32Array<any>,
    sharedParams: Float32Array<any>
  ) {
    return new VoiceState(state, samples, sharedParams);
  }

  private constructor(
    public readonly _state: Float32Array<any>,
    public readonly _samples: Float32Array<any>,
    public readonly _sharedParams: Float32Array<any>
  ) {}

  // generic access by index (escape hatch for code that fans out over param numbers)

  getParam(index: number): number {
    return this._state[index];
  }

  setParam(index: number, value: number): void {
    this._state[index] = value;
  }

  // parameters

  // gain and tempo are shared by all voices + the effect (see _sharedParams)

  get gain() {
    return this._sharedParams[SP_GAIN];
  }

  set gain(value: number) {
    this._sharedParams[SP_GAIN] = value;
  }

  get tempo() {
    return this._sharedParams[SP_TEMPO];
  }

  set tempo(value: number) {
    this._sharedParams[SP_TEMPO] = value;
  }

  get glide() {
    return this._state[P_GLIDE];
  }

  set glide(value: number) {
    this._state[P_GLIDE] = value;
  }

  get slide() {
    return this._state[P_SLIDE];
  }

  set slide(value: number) {
    this._state[P_SLIDE] = value;
  }

  get pressure() {
    return this._state[P_PRESSURE];
  }

  set pressure(value: number) {
    this._state[P_PRESSURE] = value;
  }

  get midiNote() {
    return this._state[P_MIDI_NOTE];
  }

  set midiNote(value: number) {
    this._state[P_MIDI_NOTE] = value;
  }

  get noteFreq0() {
    return this._state[P_NOTE_FREQ0];
  }

  set noteFreq0(value: number) {
    this._state[P_NOTE_FREQ0] = value;
  }

  get noteFreq() {
    return this._state[P_NOTE_FREQ];
  }

  set noteFreq(value: number) {
    this._state[P_NOTE_FREQ] = value;
  }

  get velocity() {
    return this._state[P_NOTE_VEL];
  }

  set velocity(value: number) {
    this._state[P_NOTE_VEL] = value;
  }

  // shared params live in the shared array (one copy per synth, not per voice)

  getSharedParam(index: number): number {
    return this._sharedParams[index];
  }

  setSharedParam(index: number, value: number): void {
    this._sharedParams[index] = value;
  }

  get paramA() {
    return this._sharedParams[SP_PARAM_A];
  }

  set paramA(value: number) {
    this._sharedParams[SP_PARAM_A] = value;
  }

  get paramB() {
    return this._sharedParams[SP_PARAM_B];
  }

  set paramB(value: number) {
    this._sharedParams[SP_PARAM_B] = value;
  }

  get paramC() {
    return this._sharedParams[SP_PARAM_C];
  }

  set paramC(value: number) {
    this._sharedParams[SP_PARAM_C] = value;
  }

  get paramD() {
    return this._sharedParams[SP_PARAM_D];
  }

  set paramD(value: number) {
    this._sharedParams[SP_PARAM_D] = value;
  }

  get paramE() {
    return this._sharedParams[SP_PARAM_E];
  }

  set paramE(value: number) {
    this._sharedParams[SP_PARAM_E] = value;
  }

  get paramF() {
    return this._sharedParams[SP_PARAM_F];
  }

  set paramF(value: number) {
    this._sharedParams[SP_PARAM_F] = value;
  }

  get paramG() {
    return this._sharedParams[SP_PARAM_G];
  }

  set paramG(value: number) {
    this._sharedParams[SP_PARAM_G] = value;
  }

  get paramH() {
    return this._sharedParams[SP_PARAM_H];
  }

  set paramH(value: number) {
    this._sharedParams[SP_PARAM_H] = value;
  }

  // voice lifecycle (busy/free is derived from the silence countdown)

  get silenceCountdown() {
    return this._state[P_SILENCE_COUNTDOWN];
  }

  /** A voice is free once it has been silent long enough. */
  get isFree() {
    return this._state[P_SILENCE_COUNTDOWN] <= 0;
  }

  get isActive() {
    return !this.isFree;
  }

  /** Claim the voice / keep it alive (resets the countdown to its full value). */
  replenishSilenceCountdown(): void {
    this._state[P_SILENCE_COUNTDOWN] = FULL_SILENCE_COUNTDOWN_FRAMES;
  }

  /** Advance the countdown by one frame of silence. */
  decrementSilenceCountdown(): void {
    if (this._state[P_SILENCE_COUNTDOWN] > 0) {
      this._state[P_SILENCE_COUNTDOWN]--;
    }
  }

  /** Immediately mark the voice free. */
  markFree(): void {
    this._state[P_SILENCE_COUNTDOWN] = 0;
  }

  // sampler states

  get numSamplerStates() {
    return this._state[NUM_SAMPLER_STATES];
  }

  clearSamplerStates() {
    this._state[NUM_SAMPLER_STATES] = 0;
  }

  addSamplerState(phase: number, _in: number, out: number, loopIn: number, loopOut: number) {
    const count = this._state[NUM_SAMPLER_STATES];
    if (count >= MAX_NUM_SAMPLER_STATES) {
      return;
    }

    const idx = NUM_SAMPLER_STATES + 1 + count * 5;
    this._state[NUM_SAMPLER_STATES] = count + 1;
    this._state[idx + 0] = phase;
    this._state[idx + 1] = _in;
    this._state[idx + 2] = out;
    this._state[idx + 3] = loopIn;
    this._state[idx + 4] = loopOut;
  }

  samplerStatesDo(
    fn: (phase: number, _in: number, out: number, loopIn: number, loopOut: number) => void,
    doFirstOneNoMatterWhat = false
  ) {
    const count = Math.max(this._state[NUM_SAMPLER_STATES], doFirstOneNoMatterWhat ? 1 : 0);
    for (let i = 0; i < count; i++) {
      const idx = NUM_SAMPLER_STATES + 1 + i * 5;
      const phase = this._state[idx + 0];
      const _in = this._state[idx + 1];
      const out = this._state[idx + 2];
      const loopIn = this._state[idx + 3];
      const loopOut = this._state[idx + 4];
      fn(phase, _in, out, loopIn, loopOut);
    }
  }
}
