import {
  SAMPLE_RATE,
  TAPE_ARROW_SPEED_MAGNITUDE,
  TAPE_LENGTH_IN_FRAMES,
  TAPE_MAX_FRAMES_PER_TRACK,
  TAU,
} from './constants';
import { Display, EmbeddedSelector, Label, Row, ThingOptions } from './things';
import { ctx, showStatus } from './canvas';
import * as ui from './ui-constants';
import { clamp, pad } from './helpers';
import TapeState from './TapeState';
import { context, masterCompressor, registerInputConsumer } from './audio';
import { MessageFromTapeWorklet, MessageToTapeWorklet } from './types';

/** UI-only: ease tape playhead over a few frames when it jumps while the transport is still. */
const TAPE_UI_JUMP_MIN_DELTA_FRAMES = 12;
const TAPE_UI_JUMP_DURATION_MS = 100;

export default class TapeTool extends Row {
  readonly tape = new Tape();
  private readonly display: Display;

  constructor(options: ThingOptions) {
    super(options);
    const tape = this.tape;
    this.display = new (class extends Display {
      constructor(readonly label: string) {
        super(options);
      }

      private tapeUiPlayhead = NaN;
      private tapeLastActualPlayhead = NaN;
      private tapeJumpAnim: { from: number; to: number; startMs: number } | null = null;

      private tapeTransportMoving() {
        return tape.state.recording || tape.state.playing || Math.abs(tape.state.speed) > 1e-5;
      }

      /** Displayed playhead (frames); audio engine uses tape.state.playhead — this is visuals only. */
      private tapeDisplayedPlayhead(): number {
        const actual = tape.state.playhead;
        if (!Number.isFinite(this.tapeLastActualPlayhead)) {
          this.tapeLastActualPlayhead = actual;
          this.tapeUiPlayhead = actual;
          return actual;
        }

        if (this.tapeTransportMoving()) {
          this.tapeUiPlayhead = actual;
          this.tapeJumpAnim = null;
          this.tapeLastActualPlayhead = actual;
          return actual;
        }

        const snapDelta = Math.abs(actual - this.tapeLastActualPlayhead);
        if (snapDelta >= TAPE_UI_JUMP_MIN_DELTA_FRAMES) {
          this.tapeJumpAnim = {
            from: this.tapeUiPlayhead,
            to: actual,
            startMs: performance.now(),
          };
        }
        this.tapeLastActualPlayhead = actual;

        if (this.tapeJumpAnim) {
          const { from, to, startMs } = this.tapeJumpAnim;
          const t = Math.min(1, (performance.now() - startMs) / TAPE_UI_JUMP_DURATION_MS);
          const eased = 1 - (1 - t) ** 3;
          this.tapeUiPlayhead = from + eased * (to - from);
          if (t >= 1) {
            this.tapeJumpAnim = null;
          }
          return this.tapeUiPlayhead;
        }

        this.tapeUiPlayhead = actual;
        return actual;
      }

      override renderDisplay() {
        const ph = this.tapeDisplayedPlayhead();
        this.renderTape(ph);
        this.renderTracks(ph);
      }

      get xScale() {
        return this.displayW / (5 * SAMPLE_RATE);
      }

      renderTracks(ph: number) {
        const xScale = this.xScale;
        const toX = (frameIdx: number) => Math.floor(this.centerX + xScale * (frameIdx - ph));

        const clipAtPlayhead = tape.state.clipAt(Math.floor(ph));

        const trackHeight = Math.floor(this.displayH / 24);
        ctx.globalAlpha = 0.8;
        tape.state.forEachClip((trackIdx, startFrameIdx, length, samplesStartIdx, offset) => {
          ctx.fillStyle =
            offset === clipAtPlayhead?.offset
              ? 'cornflowerblue'
              : trackIdx === tape.state.selectedTrackIdx
                ? '#eee'
                : '#aaa';
          ctx.fillRect(
            toX(startFrameIdx),
            this.displayY + this.displayH - trackHeight * (4 - trackIdx) - ui.LABEL_PADDING,
            Math.floor(xScale * length - 1),
            trackHeight - 1
          );
        });

        // time notches
        ctx.globalAlpha = 0.5;
        ctx.fillStyle = '#ddd';
        const framesPerDiv = tape.state.getFramesPerDiv();
        for (let frameIdx = 0; frameIdx < TAPE_LENGTH_IN_FRAMES; frameIdx += framesPerDiv) {
          ctx.fillRect(
            toX(frameIdx),
            this.displayY + this.displayH - trackHeight * 4 - 2 * ui.LABEL_PADDING,
            1,
            trackHeight - 1
          );
        }

        // loop in/out markers
        if (tape.state.loopInPoint >= 0 || tape.state.loopOutPoint <= TAPE_LENGTH_IN_FRAMES) {
          ctx.save();
          ctx.globalAlpha = 1;
          ctx.fillStyle = tape.state.loopOn ? 'yellow' : '#ddd';
          const inPoint = clamp(tape.state.loopInPoint, 0, TAPE_LENGTH_IN_FRAMES);
          const outPoint = clamp(tape.state.loopOutPoint, 0, TAPE_LENGTH_IN_FRAMES);
          const inX = toX(inPoint);
          const outX = toX(outPoint);
          const y = this.displayY + this.displayH - trackHeight * 3.5 - 2 * ui.LABEL_PADDING - 0.5;
          ctx.fillRect(inX, y - 0.5, outX - inX, 1);

          const triangle = (x: number, dir: number) => {
            ctx.beginPath();
            ctx.moveTo(x - dir * 2, y);
            ctx.lineTo(x + dir * 4, y - 3);
            ctx.lineTo(x + dir * 4, y + 3);
            ctx.closePath();
            ctx.fill();
          };
          triangle(inX, -1);
          triangle(outX, 1);

          ctx.restore();
        }

        // end markers
        ctx.globalAlpha = 1;
        ctx.fillRect(
          toX(0) - 2,
          this.displayY + this.displayH - trackHeight * 4 - ui.LABEL_PADDING,
          2,
          trackHeight * 4
        );
        ctx.fillRect(
          toX(TAPE_LENGTH_IN_FRAMES) + 2,
          this.displayY + this.displayH - trackHeight * 4 - ui.LABEL_PADDING,
          2,
          trackHeight * 4
        );

        // playhead
        ctx.fillStyle = '#fff';
        const h = trackHeight * 4 + ui.LABEL_PADDING;
        ctx.fillRect(
          this.centerX,
          this.displayY + this.displayH - h - ui.LABEL_PADDING,
          1,
          h + 0.5 * ui.LABEL_PADDING
        );
      }

      get micOn() {
        return tape.inputGain && tape.inputGain.gain.value > 0;
      }

      renderTape(ph: number) {
        const tapePct = ph / TAPE_LENGTH_IN_FRAMES;
        const size = this.options.h!() / 2 / 2.5; // outer radius of each reel
        const reelRadius = size;
        const reelInnermostRadius = reelRadius / 5;
        const reelNextToInnermostRadius = reelInnermostRadius + 3;
        const reelY = 1.9 * size;
        const innerCircleRadius = 0.15 * size;
        const innerCircleY = reelY + 1.25 * size;
        const outerCircleRadius = 0.08 * size;
        const outerCirclePosAdjustment =
          tape.state.recording || tape.state.playing ? 0.05 * size : 0;
        const outerCircleY = reelY + 1.4 * size - outerCirclePosAdjustment;
        const playheadW = size / 3;
        const playheadH = size / 4;
        const playheadBottomY =
          innerCircleY +
          playheadH / 2 +
          (tape.state.recording || tape.state.playing ? size / 10 : 0);
        const whiteOrRed = tape.state.recording ? '#ff3333' : '#eee';

        // write the time
        const ps = ph / SAMPLE_RATE;
        const m = Math.floor(ps / 60);
        const s = Math.floor(ps) % 60;
        const c = Math.floor(ps * 100) % 100;
        const t = `${m}:${pad(s)}.${pad(c)}`;
        ctx.font = 'normal 300 24px Roboto Mono';
        ctx.textAlign = 'center';
        ctx.fillStyle = '#fff';
        ctx.fillText(t, this.centerX, this.displayY + 0.75 * size);

        const symbolSize = size / 4;

        // draw the speed indicator
        const speedIndicatorY = reelY - 3.25 * symbolSize;
        const speedIndicatorH = 1.25 * symbolSize;
        const speedIndicatorW = 6 * symbolSize;
        for (let d = -1; d <= 1; d += 0.5) {
          ctx.strokeStyle = '#888';
          ctx.lineWidth = 2;
          ctx.beginPath();
          const ad = Math.abs(d);
          const dh = ad === 1 ? 0.5 : ad === 0.5 ? 0.6 : 0;
          ctx.moveTo(
            this.centerX + (d * speedIndicatorW) / 2,
            speedIndicatorY + (dh / 2) * speedIndicatorH
          );
          ctx.lineTo(
            this.centerX + (d * speedIndicatorW) / 2,
            speedIndicatorY + (1 - dh / 2) * speedIndicatorH
          );
          ctx.stroke();
        }
        const speedIndicatorX =
          this.centerX + (speedIndicatorW * tape.state.speed) / TAPE_ARROW_SPEED_MAGNITUDE / 2;
        ctx.strokeStyle = '#fff';
        ctx.beginPath();
        ctx.moveTo(speedIndicatorX, speedIndicatorY);
        ctx.lineTo(speedIndicatorX, speedIndicatorY + speedIndicatorH);
        ctx.stroke();

        const onColor = '#fff';
        const offColor = '#555';

        // draw the rec/play/loop indicator between the reels
        if (tape.state.recording) {
          ctx.fillStyle = '#ff3333';
          ctx.beginPath();
          ctx.arc(this.centerX, reelY, symbolSize, 0, TAU);
          ctx.fill();
        } else if (tape.state.playingDirection === 1) {
          ctx.fillStyle = '#fff';
          ctx.beginPath();
          ctx.moveTo(this.centerX + symbolSize, reelY);
          ctx.lineTo(this.centerX - symbolSize, reelY + symbolSize);
          ctx.lineTo(this.centerX - symbolSize, reelY - symbolSize);
          ctx.fill();
        } else if (tape.state.playingDirection === -1) {
          ctx.fillStyle = '#fff';
          ctx.beginPath();
          ctx.moveTo(this.centerX - symbolSize, reelY);
          ctx.lineTo(this.centerX + symbolSize, reelY + symbolSize);
          ctx.lineTo(this.centerX + symbolSize, reelY - symbolSize);
          ctx.fill();
        } else {
          const loopSize = 1.25 * symbolSize;
          ctx.strokeStyle = tape.state.loopOn ? onColor : offColor;
          ctx.lineWidth = 2;
          ctx.beginPath();
          ctx.roundRect(
            this.centerX - loopSize,
            reelY - loopSize / 2,
            2 * loopSize,
            loopSize,
            loopSize
          );
          ctx.stroke();
          const triangleSize = 0.4 * loopSize;
          const triangleY = reelY - loopSize / 2 - 0.5;
          ctx.fillStyle = '#000';
          ctx.fillRect(
            this.centerX - 0.75 * triangleSize,
            reelY - loopSize,
            (2 * loopSize) / 5,
            loopSize
          );
          ctx.fillStyle = tape.state.loopOn ? onColor : offColor;
          ctx.beginPath();
          ctx.moveTo(this.centerX + 0.5 * triangleSize, triangleY - triangleSize / 2);
          ctx.lineTo(this.centerX + 0.5 * triangleSize, triangleY + triangleSize);
          ctx.lineTo(this.centerX - 0.5 * triangleSize, triangleY);
          ctx.closePath();
          ctx.fill();
        }

        // draw the mic
        const rightMargin = this.displayX + this.displayW - ui.LABEL_PADDING;
        const topMargin = this.displayY + 2 * ui.LABEL_PADDING + ui.Font.label.sizeInPixels;
        const micHeadRadius = symbolSize / 2;
        const micHeadX = rightMargin - micHeadRadius;
        const micHeadY = topMargin + micHeadRadius;
        const micHandleBottomY = topMargin + 2 * symbolSize;
        const micHandleBottomX = rightMargin - 2 * symbolSize;
        ctx.fillStyle = ctx.strokeStyle = this.micOn ? onColor : offColor;
        ctx.beginPath();
        ctx.arc(micHeadX, micHeadY, micHeadRadius, 0, TAU);
        ctx.fill();
        ctx.lineWidth = micHeadRadius / 1.5;
        ctx.lineCap = 'round';
        ctx.beginPath();
        ctx.moveTo(micHandleBottomX, micHandleBottomY);
        ctx.lineTo(micHeadX, micHeadY);
        ctx.stroke();

        // draw the metronome
        const metronomeTopY = micHandleBottomY + symbolSize;
        const metronomeRightX = rightMargin - 0.25 * symbolSize;
        const metronomeMiddleX = rightMargin - symbolSize;
        const metronomeLeftX = rightMargin - 1.75 * symbolSize;
        const metronomeBottomY = metronomeTopY + 2 * symbolSize;
        ctx.strokeStyle = ctx.fillStyle = tape.state.clickOn ? onColor : offColor;
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(metronomeMiddleX, metronomeTopY);
        ctx.lineTo(metronomeRightX, metronomeBottomY);
        ctx.lineTo(metronomeLeftX, metronomeBottomY);
        ctx.closePath();
        ctx.moveTo(metronomeMiddleX, metronomeBottomY - 0.5 * symbolSize);
        const metronomeBallX =
          tape.state.metronomeStickDirection > 0 ? metronomeRightX : metronomeLeftX;
        ctx.lineTo(metronomeBallX, metronomeTopY);
        ctx.stroke();
        ctx.beginPath();
        ctx.arc(metronomeBallX, metronomeTopY, symbolSize / 3.5, 0, TAU);
        ctx.fill();

        // draw the reel
        ctx.save();
        ctx.lineWidth = 2;
        ctx.lineJoin = 'round';
        ctx.lineCap = 'round';
        const theta = -ps * 1.5; // TODO: do it right!
        for (let d = -1; d <= 1; d += 2) {
          const playheadX = this.centerX + (d * playheadW) / 2;
          const reelX = this.centerX + d * 2 * reelRadius;
          const innerCircleX = this.centerX + d * 1.25 * size;
          const outerCircleX = reelX - d * outerCirclePosAdjustment;
          const tapeFraction = d < 0 ? 1 - tapePct : tapePct;
          const accumulatedTapeRadius = (0.4 + 0.2 * tapeFraction) * reelRadius;

          // tape accumulating in the reel
          ctx.fillStyle = '#777';
          ctx.beginPath();
          ctx.arc(reelX, reelY, accumulatedTapeRadius, 0, TAU);
          ctx.fill();
          ctx.fillStyle = '#000';
          ctx.beginPath();
          ctx.arc(reelX, reelY, reelNextToInnermostRadius, 0, TAU);
          ctx.fill();

          ctx.strokeStyle = '#777';

          // tape from the inner circle to the read/write head
          ctx.beginPath();
          ctx.moveTo(innerCircleX, innerCircleY - 0.75 * innerCircleRadius);
          ctx.lineTo(playheadX, playheadBottomY);
          ctx.stroke();

          // tape from the outer circle to the inner circle
          ctx.beginPath();
          ctx.moveTo(outerCircleX, outerCircleY + 0.75 * outerCircleRadius);
          ctx.lineTo(innerCircleX, innerCircleY - 0.75 * innerCircleRadius);
          ctx.stroke();

          // tape from the reel to the outer circle
          ctx.beginPath();
          ctx.moveTo(
            reelX + d * (accumulatedTapeRadius - 0.05 * reelRadius),
            reelY + 0.05 * reelRadius
          );
          ctx.lineTo(outerCircleX, outerCircleY + 0.75 * outerCircleRadius);
          ctx.stroke();

          ctx.strokeStyle = ctx.fillStyle = whiteOrRed;

          // inner circle
          ctx.beginPath();
          ctx.arc(innerCircleX, innerCircleY, innerCircleRadius, 0, TAU);
          ctx.fill();

          // outer circle
          ctx.fillStyle = '#000';
          ctx.beginPath();
          ctx.arc(outerCircleX, outerCircleY, outerCircleRadius, 0, TAU);
          ctx.fill();
          ctx.strokeStyle = whiteOrRed;
          ctx.beginPath();
          ctx.arc(outerCircleX, outerCircleY, outerCircleRadius, 0, TAU);
          ctx.stroke();

          // outermost circle for reels
          ctx.beginPath();
          ctx.arc(reelX, reelY, size, 0, TAU);
          ctx.stroke();
          // next-to-innermost circle for reels
          ctx.beginPath();
          ctx.arc(reelX, reelY, reelNextToInnermostRadius, 0, TAU);
          ctx.stroke();
          // innermost circle for reels
          ctx.beginPath();
          ctx.arc(reelX, reelY, reelInnermostRadius, 0, TAU);
          ctx.stroke();

          for (let idx = 0; idx < 3; idx++) {
            // big lines radiating from the centers of the reels
            const t1 = theta + (d * Math.PI) / 5 + (idx * TAU) / 3;
            ctx.beginPath();
            ctx.moveTo(
              reelX + 0.45 * reelRadius * Math.cos(t1),
              reelY + 0.45 * reelRadius * Math.sin(t1)
            );
            ctx.lineTo(
              reelX + 0.8 * reelRadius * Math.cos(t1),
              reelY + 0.8 * reelRadius * Math.sin(t1)
            );
            ctx.stroke();

            // tiny lines radiating from the centers of the reels
            const t2 = t1 + Math.PI / 3;
            ctx.beginPath();
            ctx.moveTo(
              reelX + reelNextToInnermostRadius * Math.cos(t2),
              reelY + reelNextToInnermostRadius * Math.sin(t2)
            );
            ctx.lineTo(
              reelX + 0.35 * reelRadius * Math.cos(t2),
              reelY + 0.35 * reelRadius * Math.sin(t2)
            );
            ctx.stroke();
          }
        }

        // read/write head (bottom edge: slight downward arc, large effective radius)
        const playheadBottomY0 = playheadBottomY + 1;
        const playheadBottomArcR = Math.max(22, 2.4 * playheadW);
        const playheadBottomSag =
          (playheadW * playheadW) / (8 * playheadBottomArcR) +
          (playheadBottomArcR -
            Math.sqrt(playheadBottomArcR * playheadBottomArcR - (playheadW / 2) * (playheadW / 2)));
        ctx.fillStyle = whiteOrRed;
        ctx.beginPath();
        ctx.moveTo(this.centerX - playheadW / 2, playheadBottomY0);
        ctx.lineTo(this.centerX - playheadW / 2, playheadBottomY - playheadH);
        ctx.lineTo(this.centerX + playheadW / 2, playheadBottomY - playheadH);
        ctx.lineTo(this.centerX + playheadW / 2, playheadBottomY0);
        ctx.quadraticCurveTo(
          this.centerX,
          playheadBottomY0 + 2 * playheadBottomSag,
          this.centerX - playheadW / 2,
          playheadBottomY0
        );
        ctx.closePath();
        ctx.fill();
        ctx.strokeStyle = '#000';
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(this.centerX, playheadBottomY - 0.5 * playheadH + 1);
        ctx.lineTo(this.centerX, playheadBottomY + 0.25 * playheadH);
        ctx.stroke();
        ctx.restore();
      }
    })('tape');
    this.addChild(this.display)
      .addChild(
        new EmbeddedSelector({
          values: [1 / 4, 1 / 8, 1 / 16, 1 / 32],
          getValue: () => tape.state.timeDiv,
          setValue: value => (tape.state.timeDiv = value),
          valueToString(value) {
            if (value === 1 / 4) {
              return 'div 1/4';
            } else if (value === 1 / 8) {
              return 'div 1/8';
            } else if (value === 1 / 16) {
              return 'div 1/16';
            } else if (value === 1 / 32) {
              return 'div 1/32';
            } else {
              return '???';
            }
          },
        }),
        'bottom left'
      )
      .addChild(
        new EmbeddedSelector({
          values: [0, 1, 2, 3],
          getValue: () => tape.state.selectedTrackIdx,
          setValue: value => (tape.state.selectedTrackIdx = value),
          valueToString: value => `track ${value + 1}`,
        }),
        'top left'
      )
      .addChild(
        Label.new({
          label: () => 'tape',
          color: () => '#eee',
          border: true,
        }),
        'top right'
      );
  }

  triggerRecordingIfRecIsDown() {
    if (this.tape.state.recButtonDown && Math.abs(this.tape.state.playingDirection) !== 1) {
      this.tape.state.playButtonDown = true;
    }
  }
}

class Tape {
  inputGain: GainNode | null = null;
  worklet: AudioWorkletNode | null = null;
  readonly gains = new Float32Array(new SharedArrayBuffer(4 * 4));
  readonly state = TapeState.new();
  readonly clipSamples = [
    new Float32Array(new SharedArrayBuffer(TAPE_MAX_FRAMES_PER_TRACK * 2 * 4)),
    new Float32Array(new SharedArrayBuffer(TAPE_MAX_FRAMES_PER_TRACK * 2 * 4)),
    new Float32Array(new SharedArrayBuffer(TAPE_MAX_FRAMES_PER_TRACK * 2 * 4)),
    new Float32Array(new SharedArrayBuffer(TAPE_MAX_FRAMES_PER_TRACK * 2 * 4)),
  ];

  constructor() {
    this.state.timeDiv = 1 / 4;
    this.state.loopOn = true;
    this.state.loopInPoint = -Infinity;
    this.state.loopOutPoint = Infinity;
    this.state.metronomeStickDirection = 1;
  }

  init() {
    this.worklet = new AudioWorkletNode(context, 'tape');
    this.sendToWorklet({
      command: 'init',
      state: this.state._state.buffer,
      clips: this.state._clips.buffer,
      clipSamples: this.clipSamples.map(sample => sample.buffer),
    });
    this.worklet.connect(masterCompressor);

    this.worklet.channelInterpretation = 'discrete';
    this.worklet.channelCount = 2;
    this.worklet.channelCountMode = 'explicit';
    this.inputGain = context.createGain();
    this.inputGain.gain.value = 0;
    registerInputConsumer(this.inputGain);
    this.inputGain.connect(this.worklet);
    this.worklet.port.onmessage = msg =>
      this.onMessageFromWorklet(msg.data as MessageFromTapeWorklet);
  }

  onMessageFromWorklet(msg: MessageFromTapeWorklet) {
    switch (msg.event) {
      case 'log': {
        showStatus(msg.message);
        break;
      }
    }
  }

  sendToWorklet(message: MessageToTapeWorklet) {
    this.worklet?.port.postMessage(message);
  }
}
