export async function setUpMidi(
  noteOn: (note: number, velocity: number) => void,
  noteOff: (note: number, velocity: number) => void,
  pitchBend: (numSemitones: number) => void
) {
  if (!navigator.requestMIDIAccess) {
    return;
  }
  const midiAccess = await navigator.requestMIDIAccess();
  const [midiInput] = [...(midiAccess.inputs as any).values()];
  if (!midiInput) {
    return;
  }

  console.log('midi input', midiInput);

  midiInput.onmidimessage = (e: MIDIMessageEvent) => {
    const [d1, d2, d3] = e.data;
    switch (d1 >> 4) {
      case 0x9: {
        const note = d2;
        const velocity = d3;
        if (velocity === 0) {
          // some devices send noteOn with vel 0 for noteOff!
          noteOff(note, velocity);
        } else {
          noteOn(note, velocity);
        }
        break;
      }
      case 0x8: {
        const note = d2;
        const velocity = d3;
        noteOff(note, velocity);
        break;
      }
      case 0xe: {
        const value = (((d3 << 7) | d2) - 8192) / 8192;
        const numSemitones = value * (value > 0 ? 3 : 12);
        pitchBend(numSemitones);
        break;
      }
    }
  };
}
